const webhookData = $('Webhook').first().json.body;
const raw = $('MongoDB — Buscar plantilla').first().json;
const tmpl = Array.isArray(raw) ? raw[0] : raw;

const parameters = webhookData.parameters || {};
const companyName = webhookData.company_name || 'Empresa Auditada';
const reportId = 'CS-RPT-' + new Date().toISOString().slice(0,10) + '-' + webhookData.attack_id;

function buildCommand(str, params) {
  if (!str) return '';
  return Object.entries(params).reduce((cmd, [key, value]) => {
    return cmd.replace(new RegExp('\\{\\{' + key + '\\}\\}', 'g'), value || '');
  }, str);
}

const useAlt = parameters.target_ip && parameters.target_ip.trim() !== '';
const finalCommand = buildCommand(
  useAlt && tmpl.command_alt ? tmpl.command_alt : tmpl.command,
  parameters
);

return [{
  json: {
    attack_id: webhookData.attack_id,
    attack_name: tmpl.name,
    mitre_id: tmpl.mitre_id,
    risk_level: tmpl.risk_level,
    wazuh_rule_id: tmpl.wazuh_rule_id,
    description: tmpl.description,
    command: finalCommand,
    parameters: parameters,
    company_name: companyName,
    report_id: reportId,
    start_timestamp: new Date().toISOString()
  }
}];
